+    ///
+    /// # Errors
+    /// Returns [`WebhookError::ReplayCacheFull`] when the cache has reached its maximum size.
+    pub fn record_event(&self, event_id: &str) -> WebhookResult<()> {
         if self.config.idempotency_enabled {
